index.html
<!DOCTYPE html>
<html lang='en'>
<head>
  <meta charset='UTF-8'>
  <meta name='viewport' content='width=device-width, initial-scale=1.0'>
  <title>Accessible Image Gallery</title>
  <link rel='stylesheet' href='styles.css'>
</head>
<body>
  <div class='mx-auto p-4 max-w-lg w-full'>
    <button class='mr-4 mb-4' aria-label='Previous image' id='prev-button'>Previous</button>
    <button class='ml-4 mb-4' aria-label='Next image' id='next-button'>Next</button>
    <div id='gallery' class='flex overflow-x-scroll overflow-y-hidden whitespace-nowrap'>
      <img src='./image1.jpg' alt='Image 1' aria-label='Image 1' class='mx-2 rounded'>
      <img src='./image2.jpg' alt='Image 2' aria-label='Image 2' class='mx-2 rounded'>
      <img src='./image3.jpg' alt='Image 3' aria-label='Image 3' class='mx-2 rounded'>
    </div>
  </div>
  <script src='script.js'></script>
</body>
</html>
styles.css
@tailwind base;
@tailwind components;
@tailwind utilities;
.gallery {
  @apply flex overflow-x-scroll overflow-y-hidden whitespace-nowrap;
}
.gallery img {
  max-width: 100%;
  height: auto;
}
.gallery button {
  @apply block w-full py-2 text-lg text-gray-700 hover:bg-gray-100;
}
script.js
const gallery = document.getElementById('gallery');
const images = gallery.children;
const prevButton = document.getElementById('prev-button');
const nextButton = document.getElementById('next-button');
let currentIndex = 0;
function updateGallery() {
  for (let i = 0; i < images.length; i++) {
    images[i].style.display = 'none';
  }
  images[currentIndex].style.display = 'block';
}
updateGallery();
prevButton.addEventListener('click', prevImage);
nextButton.addEventListener('click', nextImage);

function prevImage() {
  if (currentIndex > 0) {
    currentIndex--;
  }
  updateGallery();
}
function nextImage() {
  if (currentIndex < images.length - 1) {
    currentIndex++;
  }
  updateGallery();
}
